                <span className="text-sm font-medium">${product.price}</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { createRoot } from 'react-dom/client';
import { Layout } from './components/Layout';
import { LandingView } from './components/LandingView';
import { MarketplaceView } from './components/MarketplaceView';
import { ProductDetail } from './components/ProductDetail';
import { Dashboard } from './components/Dashboard';
import { FeatureFlags, Product, UserRole, ViewState } from './types';

const App: React.FC = () => {
  // State
  const [currentView, setCurrentView] = useState<ViewState>('LANDING');
  const [userRole, setUserRole] = useState<UserRole>(UserRole.BUYER);
  const [cart, setCart] = useState<Product[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);

  // Feature Flags Management
  const [featureFlags, setFeatureFlags] = useState<FeatureFlags>({
    enableMarketplace: true,
    enableReviews: true,
    enableAiStyleMatch: true,
    maintenanceMode: false
  });

  // Handlers
  const handleNavigate = (view: ViewState) => {
    setCurrentView(view);
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setIsCartOpen(false);
  };

  const handleProductSelect = (product: Product) => {
    setSelectedProduct(product);
    handleNavigate('PRODUCT_DETAIL');
  };

  const handleAddToCart = (product: Product) => {
    setCart([...cart, product]);
    setIsCartOpen(true); // Open cart when item added
  };

  const handleRemoveFromCart = (index: number) => {
    const newCart = [...cart];
    newCart.splice(index, 1);
    setCart(newCart);
  };

  const toggleFeatureFlag = (key: keyof FeatureFlags) => {
    setFeatureFlags(prev => ({ ...prev, [key]: !prev[key] }));
  };

  // View Routing
  const renderView = () => {
    if (featureFlags.maintenanceMode && userRole !== UserRole.ADMIN) {
      return (
        <div className="h-screen flex items-center justify-center flex-col">
          <h1 className="text-4xl font-serif">LUMIERRE</h1>
          <p className="mt-4 uppercase tracking-widest text-sm">Under Maintenance</p>
        </div>
      );
    }

    switch (currentView) {
      case 'LANDING':
        return <LandingView onNavigate={handleNavigate} />;
      case 'MARKETPLACE':
        return <MarketplaceView onNavigate={handleNavigate} onProductSelect={handleProductSelect} />;
      case 'PRODUCT_DETAIL':
        return selectedProduct ? (
          <ProductDetail 
            product={selectedProduct} 
            onAddToCart={handleAddToCart} 
            onBack={() => handleNavigate('MARKETPLACE')}
            featureFlags={featureFlags}
          />
        ) : <MarketplaceView onNavigate={handleNavigate} onProductSelect={handleProductSelect} />;
      case 'VENDOR_DASHBOARD':
      case 'ADMIN_PANEL':
        return (
          <Dashboard 
            role={userRole} 
            featureFlags={featureFlags} 
            toggleFeatureFlag={toggleFeatureFlag}
          />
        );
      default:
        return <LandingView onNavigate={handleNavigate} />;
    }
  };

  return (
    <Layout 
      role={userRole} 
      cart={cart}
      isCartOpen={isCartOpen}
      setIsCartOpen={setIsCartOpen}
      onRemoveFromCart={handleRemoveFromCart}
      onNavigate={handleNavigate}
      onRoleChange={setUserRole}
      currentView={currentView}
    >
      {renderView()}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ShoppingBag, Menu, X, Search, User, Globe, Trash2, ArrowRight } from 'lucide-react';
import { NAV_LINKS } from '../constants';
import { UserRole, ViewState, Product } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  role: UserRole;
  cart: Product[];
  isCartOpen: boolean;
  setIsCartOpen: (isOpen: boolean) => void;
  onRemoveFromCart: (index: number) => void;
  onNavigate: (view: ViewState) => void;
  onRoleChange: (role: UserRole) => void;
  currentView: ViewState;
}

export const Layout: React.FC<LayoutProps> = ({ 
  children, 
  role, 
  cart,
  isCartOpen,
  setIsCartOpen,
  onRemoveFromCart,
  onNavigate,
  onRoleChange,
  currentView
}) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const cartTotal = cart.reduce((sum, item) => sum + item.price, 0);

  return (
    <div className="min-h-screen bg-luxury-cream text-luxury-black font-sans selection:bg-luxury-gold selection:text-white transition-colors duration-500">
      {/* Navigation */}
      <nav 
        className={`fixed top-0 w-full z-50 transition-all duration-300 border-b border-transparent ${
          isScrolled || mobileMenuOpen ? 'bg-white/95 backdrop-blur-md border-gray-100 py-3' : 'bg-transparent py-6'
        }`}
      >
        <div className="max-w-7xl mx-auto px-6 flex justify-between items-center">

          {/* Mobile Menu Button */}
          <button className="md:hidden" onClick={() => setMobileMenuOpen(!mobileMenuOpen)}>
            {mobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
          </button>

          {/* Logo */}
          <div 
            className="text-2xl md:text-3xl font-serif font-bold tracking-widest cursor-pointer hover:opacity-70 transition-opacity"
            onClick={() => onNavigate('LANDING')}
          >
            LUMIERRE
          </div>

          {/* Desktop Nav */}
          <div className="hidden md:flex gap-8 text-xs font-medium tracking-widest uppercase">
            {NAV_LINKS.map((link) => (
              <a 
                key={link.label} 
                onClick={() => onNavigate('MARKETPLACE')}
                className="hover:text-luxury-gold transition-colors cursor-pointer"
              >
                {link.label}
              </a>
            ))}
          </div>

          {/* Icons */}
          <div className="flex items-center gap-6">
            <Search size={20} className="cursor-pointer hover:text-luxury-gold transition-colors hidden sm:block" />

            <div className="relative group">
              <User size={20} className="cursor-pointer hover:text-luxury-gold transition-colors" />
              {/* Role Switcher Dropdown (Simulation) */}
              <div className="absolute right-0 top-full mt-2 w-48 bg-white border border-gray-100 shadow-xl opacity-0 group-hover:opacity-100 invisible group-hover:visible transition-all duration-200">
                <div className="p-2 text-xs uppercase tracking-wider text-gray-400 border-b">Switch View</div>
                {Object.values(UserRole).map((r) => (
                  <button
                    key={r}
                    onClick={() => {
                      onRoleChange(r);
                      if (r === UserRole.ADMIN) onNavigate('ADMIN_PANEL');
                      else if (r === UserRole.VENDOR) onNavigate('VENDOR_DASHBOARD');
                      else onNavigate('LANDING');
                    }}
                    className={`block w-full text-left px-4 py-2 text-sm hover:bg-gray-50 ${role === r ? 'font-bold' : ''}`}
                  >
                    {r}
                  </button>
                ))}
              </div>
            </div>

            <div 
              className="relative cursor-pointer hover:text-luxury-gold transition-colors" 
              onClick={() => setIsCartOpen(true)}
            >
              <ShoppingBag size={20} />
              {cart.length > 0 && (
                <span className="absolute -top-2 -right-2 bg-luxury-black text-white text-[10px] w-4 h-4 flex items-center justify-center rounded-full">
                  {cart.length}
                </span>
              )}
            </div>
          </div>
        </div>

        {/* Mobile Menu Overlay */}
        {mobileMenuOpen && (
          <div className="md:hidden absolute top-full left-0 w-full bg-white border-b border-gray-100 py-8 px-6 flex flex-col gap-6 animate-slide-up h-screen">
             {NAV_LINKS.map((link) => (
              <a 
                key={link.label} 
                onClick={() => { setMobileMenuOpen(false); onNavigate('MARKETPLACE'); }}
                className="text-lg font-serif italic hover:text-luxury-gold transition-colors"
              >
                {link.label}
              </a>
            ))}
          </div>
        )}
      </nav>

      {/* Cart Drawer Overlay */}
      <div 
        className={`fixed inset-0 z-[60] transition-visibility duration-500 ${isCartOpen ? 'visible' : 'invisible'}`}
      >
        {/* Backdrop */}
        <div 
          className={`absolute inset-0 bg-black/40 backdrop-blur-sm transition-opacity duration-500 ${isCartOpen ? 'opacity-100' : 'opacity-0'}`}
          onClick={() => setIsCartOpen(false)}
        />

        {/* Drawer Panel */}
        <div 
          className={`absolute right-0 top-0 h-full w-full max-w-md bg-white shadow-2xl transform transition-transform duration-500 ease-out flex flex-col ${isCartOpen ? 'translate-x-0' : 'translate-x-full'}`}
        >
          {/* Cart Header */}
          <div className="p-6 border-b border-gray-100 flex justify-between items-center bg-white z-10">
             <h2 className="text-xl font-serif italic">Your Selection</h2>
             <button onClick={() => setIsCartOpen(false)} className="hover:rotate-90 transition-transform duration-300">
               <X size={24} />
             </button>
          </div>

          {/* Cart Items */}
          <div className="flex-1 overflow-y-auto p-6 space-y-8">
            {cart.length === 0 ? (
              <div className="h-full flex flex-col items-center justify-center text-gray-400">
                <ShoppingBag size={48} className="mb-4 opacity-20" />
                <p className="text-sm uppercase tracking-widest">Your bag is empty</p>
                <button 
                  onClick={() => { setIsCartOpen(false); onNavigate('MARKETPLACE'); }}
                  className="mt-6 text-xs underline hover:text-black"
                >
                  Start Shopping
                </button>
              </div>
            ) : (
              cart.map((item, index) => (
                <div key={`${item.id}-${index}`} className="flex gap-4 animate-fade-in">
                  <div className="w-24 h-32 bg-gray-100 shrink-0">
                    <img src={item.image} alt={item.name} className="w-full h-full object-cover" />
                  </div>
                  <div className="flex-1 flex flex-col justify-between py-1">
                    <div>
                      <h3 className="text-xs font-bold uppercase tracking-widest mb-1">{item.designer}</h3>
                      <p className="font-serif italic text-sm text-gray-600 leading-tight">{item.name}</p>
                      <p className="text-xs text-gray-400 mt-2">Size: M (Sample)</p>
                    </div>
                    <div className="flex justify-between items-end">
                      <span className="text-sm font-medium">${item.price}</span>
                      <button 
                        onClick={() => onRemoveFromCart(index)}
                        className="text-gray-400 hover:text-red-600 transition-colors"
                      >
                        <Trash2 size={16} />
                      </button>
                    </div>
                  </div>
                </div>
              ))
            )}
          </div>

          {/* Cart Footer */}
          {cart.length > 0 && (
            <div className="p-6 bg-gray-50 border-t border-gray-100">
              <div className="flex justify-between items-center mb-6 text-sm">
                <span className="uppercase tracking-widest text-gray-500">Subtotal</span>
                <span className="font-bold text-lg">${cartTotal}</span>
              </div>
              <button className="w-full bg-luxury-black text-white py-4 text-xs font-bold uppercase tracking-[0.2em] hover:bg-luxury-gold transition-colors flex items-center justify-center gap-2 group">
                Checkout
                <ArrowRight size={16} className="group-hover:translate-x-1 transition-transform" />
              </button>
            </div>
          )}
        </div>
      </div>

      {/* Main Content */}
      <main className="pt-20 min-h-screen">
        {children}
      </main>

      {/* Footer */}
      <footer className="bg-luxury-black text-luxury-cream py-20 px-6 mt-20">
        <div className="max-w-7xl mx-auto grid grid-cols-1 md:grid-cols-4 gap-12">
          <div>
            <h3 className="text-2xl font-serif font-bold tracking-widest mb-6">LUMIERRE</h3>
            <p className="text-gray-400 text-sm leading-relaxed max-w-xs">
