import React, { useState, useMemo } from 'react';
import { Filter, ChevronDown, Heart } from 'lucide-react';
import { MOCK_PRODUCTS } from '../constants';
import { Product, ViewState } from '../types';

interface MarketplaceViewProps {
  onProductSelect: (product: Product) => void;
  onNavigate: (view: ViewState) => void;
}

const FILTERS = ['All', 'Outerwear', 'Bottoms', 'Knitwear', 'Footwear', 'Accessories'];

export const MarketplaceView: React.FC<MarketplaceViewProps> = ({ onProductSelect }) => {
  const [activeCategory, setActiveCategory] = useState('All');
  const [activeDesigner, setActiveDesigner] = useState('All Designers');

  // Extract unique designers
  const designers = useMemo(() => {
    const unique = Array.from(new Set(MOCK_PRODUCTS.map(p => p.designer)));
    return ['All Designers', ...unique.sort()];
  }, []);

  const filteredProducts = MOCK_PRODUCTS.filter(p => {
    const matchesCategory = activeCategory === 'All' || p.category === activeCategory;
    const matchesDesigner = activeDesigner === 'All Designers' || p.designer === activeDesigner;
    return matchesCategory && matchesDesigner;
  });

  return (
    <div className="min-h-screen pt-12 pb-24">
      {/* Header & Filters */}
      <div className="max-w-7xl mx-auto px-6 mb-12 sticky top-20 z-30 bg-white/80 backdrop-blur-sm py-6 border-b border-gray-100/50 transition-all">
        <div className="flex flex-col gap-8">

          {/* Top Row: Title + Designer Select */}
          <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
            <h1 className="text-4xl font-serif italic">Ready-to-Wear</h1>

            {/* Designer Dropdown */}
            <div className="relative min-w-[240px]">
              <label className="text-[10px] uppercase tracking-widest text-gray-400 mb-2 block font-bold">Filter by Designer</label>
              <div className="relative group">
                <select 
                  value={activeDesigner}
                  onChange={(e) => setActiveDesigner(e.target.value)}
                  className="w-full appearance-none bg-transparent border-b border-gray-300 py-2 pr-8 text-sm font-bold uppercase tracking-widest focus:outline-none focus:border-black cursor-pointer hover:border-luxury-gold transition-colors"
                >
                  {designers.map(d => (
                    <option key={d} value={d}>{d}</option>
                  ))}
                </select>
                <ChevronDown size={14} className="absolute right-0 top-1/2 -translate-y-1/2 pointer-events-none text-gray-400 group-hover:text-black transition-colors" />
              </div>
            </div>
          </div>

          {/* Bottom Row: Category Pills */}
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3 overflow-x-auto w-full pb-2 scrollbar-hide">
              {FILTERS.map(cat => (
                <button
                  key={cat}
                  onClick={() => setActiveCategory(cat)}
                  className={`text-xs uppercase tracking-widest whitespace-nowrap px-6 py-2 border rounded-full transition-all duration-300 ${
                    activeCategory === cat 
                      ? 'bg-black text-white border-black' 
                      : 'bg-transparent text-gray-500 border-gray-200 hover:border-black hover:text-black'
                  }`}
                >
                  {cat}
                </button>
              ))}
            </div>
             <button className="hidden md:flex items-center gap-2 text-xs uppercase font-bold ml-4 border-l pl-6 border-gray-200 hover:text-luxury-gold transition-colors whitespace-nowrap">
              <Filter size={14} /> More Filters
            </button>
          </div>

        </div>
      </div>

      {/* Grid */}
      <div className="max-w-7xl mx-auto px-6">
        {filteredProducts.length === 0 ? (
           <div className="py-24 text-center animate-fade-in">
             <p className="text-xl font-serif italic text-gray-400 mb-4">No pieces found matching your criteria.</p>
             <button 
               onClick={() => {setActiveCategory('All'); setActiveDesigner('All Designers');}} 
               className="text-xs font-bold uppercase border-b border-black pb-1 hover:text-luxury-gold hover:border-luxury-gold transition-colors"
             >
               Clear Filters
             </button>
           </div>
        ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-x-6 gap-y-16 animate-fade-in">
          {filteredProducts.map((product) => (
            <div 
              key={product.id} 
              className="group cursor-pointer"
              onClick={() => onProductSelect(product)}
            >
              <div className="relative aspect-[3/4] overflow-hidden bg-gray-100 mb-6">
                <img 
                  src={product.image} 
                  alt={product.name} 
                  className="w-full h-full object-cover transition-transform duration-700 ease-out group-hover:scale-110"
                />

                {/* Overlay Action */}
                <div className="absolute inset-0 bg-black/10 transition-opacity duration-500 opacity-0 group-hover:opacity-100 flex items-end justify-center pb-8">
                  <button className="bg-white text-black text-xs font-bold uppercase tracking-widest px-8 py-3 hover:bg-luxury-black hover:text-white transition-all duration-500 shadow-xl transform translate-y-4 opacity-0 group-hover:translate-y-0 group-hover:opacity-100">
                    Quick View
                  </button>
                </div>

                <button className="absolute top-4 right-4 text-white mix-blend-difference hover:scale-110 transition-transform opacity-0 group-hover:opacity-100 duration-500">
                  <Heart size={20} strokeWidth={1.5} />
                </button>
              </div>

              <div className="flex justify-between items-start">
                <div>
                  <h3 className="text-xs font-bold uppercase tracking-widest mb-1">{product.designer}</h3>
                  <p className="font-serif text-gray-600 italic group-hover:text-black transition-colors">{product.name}</p>
                </div>
                <span className="text-sm font-medium">${product.price}</span>
              </div>
            </div>
          ))}
        </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Star, Truck, ShieldCheck, Sparkles } from 'lucide-react';
import { Product } from '../types';
import { getStyleMatch } from '../services/geminiService';

interface ProductDetailProps {
  product: Product;
  onAddToCart: (product: Product) => void;
  onBack: () => void;
  featureFlags: { enableAiStyleMatch: boolean; enableReviews: boolean; };
}

export const ProductDetail: React.FC<ProductDetailProps> = ({ product, onAddToCart, onBack, featureFlags }) => {
  const [selectedSize, setSelectedSize] = useState<string | null>(null);
  const [styleTip, setStyleTip] = useState<string | null>(null);
  const [loadingStyle, setLoadingStyle] = useState(false);
  const [activeImage, setActiveImage] = useState(product.image);

  useEffect(() => {
    setActiveImage(product.image);
    setSelectedSize(null);
    setStyleTip(null);
  }, [product]);

  // Generate mock additional images for the gallery
  const galleryImages = [
    product.image,
    `https://picsum.photos/seed/${product.id}detail1/800/1200`,
    `https://picsum.photos/seed/${product.id}detail2/800/1200`,
    `https://picsum.photos/seed/${product.id}detail3/800/1200`,
  ];

  const handleStyleMatch = async () => {
    setLoadingStyle(true);
    const tip = await getStyleMatch(product.name);
    setStyleTip(tip);
    setLoadingStyle(false);
  };

  return (
    <div className="min-h-screen bg-white animate-fade-in">
      <div className="max-w-7xl mx-auto px-6 py-12">
        <button onClick={onBack} className="text-xs uppercase font-bold tracking-widest mb-8 hover:text-luxury-gold transition-colors">
          ← Back to Marketplace
        </button>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-16">
          {/* Gallery */}
          <div className="space-y-4">
            {/* Main Image */}
            <div className="aspect-[3/4] overflow-hidden bg-gray-50 cursor-zoom-in">
              <img 
                src={activeImage} 
                alt={product.name} 
                className="w-full h-full object-cover hover:scale-110 transition-transform duration-700 ease-out" 
              />
            </div>
            {/* Thumbnails */}
            <div className="grid grid-cols-4 gap-4">
              {galleryImages.map((img, idx) => (
                <button 
                  key={idx}
                  onClick={() => setActiveImage(img)}
                  className={`aspect-[3/4] bg-gray-50 overflow-hidden transition-all duration-300 ${
                    activeImage === img 
                      ? 'ring-1 ring-black ring-offset-2 opacity-100' 
                      : 'opacity-60 hover:opacity-100'
                  }`}
                >
                  <img src={img} alt={`View ${idx + 1}`} className="w-full h-full object-cover" />
                </button>
              ))}
            </div>
          </div>

          {/* Info */}
          <div className="sticky top-32 h-fit space-y-8">
            <div>
              <div className="flex justify-between items-start mb-2">
                <h2 className="text-xl font-bold uppercase tracking-widest">{product.designer}</h2>
                <div className="flex items-center gap-1">
                  <Star size={14} className="fill-luxury-gold text-luxury-gold" />
                  <span className="text-xs font-medium">{product.rating} (42 Reviews)</span>
                </div>
              </div>
              <h1 className="text-4xl font-serif italic mb-4">{product.name}</h1>
              <p className="text-2xl font-light">${product.price}</p>
            </div>

            <p className="text-gray-600 leading-relaxed font-light">
              {product.description} Constructed with precision and tailored for the modern silhouette. 
              This piece embodies the philosophy of {product.designer}, merging utility with high-fashion aesthetics.
            </p>

            {/* AI Style Match */}
            {featureFlags.enableAiStyleMatch && (
              <div className="p-6 bg-luxury-cream border border-luxury-gold/20 rounded-sm">
                <div className="flex items-center gap-2 mb-3">
                  <Sparkles size={16} className="text-luxury-gold" />
                  <h4 className="text-xs font-bold uppercase tracking-widest">LUMIERRE AI Stylist</h4>
                </div>
                {styleTip ? (
                  <p className="text-sm font-serif italic text-gray-700 animate-fade-in">"{styleTip}"</p>
                ) : (
                  <button 
                    onClick={handleStyleMatch}
                    disabled={loadingStyle}
                    className="text-xs underline hover:text-luxury-gold disabled:opacity-50"
                  >
                    {loadingStyle ? 'Curating advice...' : 'Get Styling Advice'}
                  </button>
                )}
              </div>
            )}

            <div className="space-y-4">
              <p className="text-xs font-bold uppercase">Select Size</p>
              <div className="flex gap-3">
                {['XS', 'S', 'M', 'L', 'XL'].map(size => (
                  <button
                    key={size}
                    onClick={() => setSelectedSize(size)}
                    className={`w-12 h-12 flex items-center justify-center border text-sm transition-all ${
                      selectedSize === size 
                        ? 'bg-black text-white border-black' 
                        : 'border-gray-200 hover:border-black'
                    }`}
                  >
                    {size}
                  </button>
                ))}
              </div>
            </div>

            <button 
              onClick={() => onAddToCart(product)}
              className="w-full bg-black text-white py-5 text-xs font-bold uppercase tracking-[0.2em] hover:bg-luxury-gold transition-colors"
            >
              Add to Bag
            </button>

            <div className="grid grid-cols-2 gap-4 text-xs text-gray-500 pt-8 border-t border-gray-100">
              <div className="flex items-center gap-2">
                <Truck size={16} />
                <span>Free Express Shipping</span>
              </div>
              <div className="flex items-center gap-2">
                <ShieldCheck size={16} />
                <span>Authenticity Guaranteed</span>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

