import React, { useState, useEffect } from 'react';
import { ShoppingBag, Menu, X, Search, User, Globe, Trash2, ArrowRight, LogOut, Settings, CheckCircle } from 'lucide-react';
import { NAV_LINKS } from '../constants';
import { UserRole, ViewState, Product } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  role: UserRole;
  cart: Product[];
  isCartOpen: boolean;
  setIsCartOpen: (isOpen: boolean) => void;
  onRemoveFromCart: (index: number) => void;
  onNavigate: (view: ViewState) => void;
  onRoleChange: (role: UserRole) => void;
  currentView: ViewState;
  isLoggedIn: boolean;
  onLogout: () => void;
}

export const Layout: React.FC<LayoutProps> = ({ 
  children, 
  role, 
  cart,
  isCartOpen,
  setIsCartOpen,
  onRemoveFromCart,
  onNavigate,
  onRoleChange,
  currentView,
  isLoggedIn,
  onLogout
}) => {
  const [isScrolled, setIsScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [orderComplete, setOrderComplete] = useState(false);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const cartTotal = cart.reduce((sum, item) => sum + item.price, 0);

  const handleDashboardClick = () => {
    if (role === UserRole.ADMIN) onNavigate('ADMIN_PANEL');
    else if (role === UserRole.VENDOR) onNavigate('VENDOR_DASHBOARD');
    else onNavigate('BUYER_DASHBOARD');
  };

  const handleCheckout = () => {
    // Simulate checkout process
    setOrderComplete(true);
    // Clear cart via parent prop simulation (In real app, dispatch to store)
    // Since we don't have a clearCart prop, we'll manually empty by calling remove on all indices (inefficient but works for demo structure) or just close visual.
