      isLoggedIn={isLoggedIn}
      onLogout={handleLogout}
    >
      {renderView()}
    </Layout>
  );
};

export default App;

export enum UserRole {
  BUYER = 'BUYER',
  VENDOR = 'VENDOR',
  ADMIN = 'ADMIN'
