              Cancel
            </button>
            <button 
              type="submit" 
              className="w-2/3 bg-black text-white py-4 text-xs font-bold uppercase tracking-widest hover:bg-luxury-gold transition-colors"
            >
              Publish to Marketplace
            </button>
