            {/* User / Auth Menu */}
            <div className="relative group">
              <User 
                size={20} 
                className={`cursor-pointer transition-colors ${isLoggedIn ? 'text-luxury-black' : 'text-gray-400 hover:text-luxury-gold'}`}
                onClick={() => !isLoggedIn && onNavigate('AUTH')}
