                      <LogOut size={14} /> Sign Out
                    </button>
                  </>
                ) : (
                  <div className="p-2">
                    <button 
                      onClick={() => onNavigate('AUTH')}
                      className="w-full bg-black text-white py-3 text-xs font-bold uppercase tracking-widest hover:bg-luxury-gold transition-colors"
