interface DashboardProps {
  role: UserRole;
  featureFlags: FeatureFlags;
  toggleFeatureFlag: (key: keyof FeatureFlags) => void;
  onNavigate: (view: ViewState) => void;
  initialTab?: DashboardTab;
}

type DashboardTab = 'OVERVIEW' | 'PRODUCTS' | 'UPLOAD' | 'ORDERS' | 'SETTINGS' | 'MARKETPLACE' | 'PROFILE';

const STANDARD_SIZES = ['XS', 'S', 'M', 'L', 'XL', 'XXL', '39', '40', '41', '42', 'One Size'];

export const Dashboard: React.FC<DashboardProps> = ({ role, featureFlags, toggleFeatureFlag, onNavigate, initialTab }) => {
  const isAdmin = role === UserRole.ADMIN;
  const isVendor = role === UserRole.VENDOR;
  const isBuyer = role === UserRole.BUYER;

  const [activeTab, setActiveTab] = useState<DashboardTab>('OVERVIEW');
  const [localProducts, setLocalProducts] = useState<Product[]>(MOCK_PRODUCTS);

  // Sync initialTab prop
  useEffect(() => {
    if (initialTab) {
      setActiveTab(initialTab);
    }
  }, [initialTab]);

  // Form State for Upload
  const [newProduct, setNewProduct] = useState<Partial<Product>>({
    name: '',
    price: 0,
    category: 'Outerwear',
    description: '',
    image: '',
    designer: 'Maison Margaux', // Hardcoded for demo
    stock: 1,
    sizes: ['S', 'M', 'L']
  });

  const handleUpload = (e: React.FormEvent) => {
    e.preventDefault();
    const product: Product = {
      id: `new-${Date.now()}`,
      name: newProduct.name || 'Untitled Piece',
      price: newProduct.price || 0,
      category: newProduct.category || 'Uncategorized',
      description: newProduct.description || '',
      image: newProduct.image || 'https://picsum.photos/600/800', // Fallback
      designer: newProduct.designer || 'Maison Margaux',
      rating: 0,
      stock: newProduct.stock || 1,
      isNewSeason: true,
      sizes: newProduct.sizes || ['M']
    };
    setLocalProducts([product, ...localProducts]);
    setActiveTab('PRODUCTS');
    // Reset form
    setNewProduct({
        name: '',
        price: 0,
        category: 'Outerwear',
        description: '',
        image: '',
        designer: 'Maison Margaux',
        stock: 1,
        sizes: ['S', 'M', 'L']
    });
  };

  const toggleSize = (size: string) => {
    const currentSizes = newProduct.sizes || [];
    if (currentSizes.includes(size)) {
        setNewProduct({...newProduct, sizes: currentSizes.filter(s => s !== size)});
    } else {
        setNewProduct({...newProduct, sizes: [...currentSizes, size]});
    }
  };

  const generateAiDescription = () => {
    // Simulation of AI generation
    setNewProduct({
      ...newProduct,
      description: "A transcendental piece featuring architectural pleats and a structured silhouette. Crafted from ethically sourced organic silk, this garment embodies the duality of modern chaos and serene minimalism."
    });
  };

  const getSidebarItems = () => {
