import React, { useState, useEffect } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, LineChart, Line, CartesianGrid 
} from 'recharts';
import { 
  Package, Users, DollarSign, Activity, Settings, ToggleRight, 
  Plus, Image as ImageIcon, LayoutDashboard, Shirt, ShoppingBag, 
  ChevronRight, Sparkles, UploadCloud, Trash2, ArrowUpRight, Eye,
  Palette, Layout, Type, FileText, Newspaper, ExternalLink
} from 'lucide-react';
import { FeatureFlags, UserRole, Product, ViewState } from '../types';
import { MOCK_PRODUCTS } from '../constants';

const SALES_DATA = [
  { name: 'Mon', sales: 4000 },
  { name: 'Tue', sales: 3000 },
  { name: 'Wed', sales: 2000 },
  { name: 'Thu', sales: 2780 },
  { name: 'Fri', sales: 1890 },
  { name: 'Sat', sales: 2390 },
  { name: 'Sun', sales: 3490 },
];

interface DashboardProps {
  role: UserRole;
  featureFlags: FeatureFlags;
  toggleFeatureFlag: (key: keyof FeatureFlags) => void;
  onNavigate: (view: ViewState) => void;
  initialTab?: DashboardTab;
}

type DashboardTab = 'OVERVIEW' | 'PRODUCTS' | 'UPLOAD' | 'ORDERS' | 'SETTINGS' | 'MARKETPLACE' | 'PROFILE' | 'STORE_DESIGN';

const STANDARD_SIZES = ['XS', 'S', 'M', 'L', 'XL', 'XXL', '39', '40', '41', '42', 'One Size'];

export const Dashboard: React.FC<DashboardProps> = ({ role, featureFlags, toggleFeatureFlag, onNavigate, initialTab }) => {
  const isAdmin = role === UserRole.ADMIN;
  const isVendor = role === UserRole.VENDOR;
  const isBuyer = role === UserRole.BUYER;

  const [activeTab, setActiveTab] = useState<DashboardTab>('OVERVIEW');
  const [localProducts, setLocalProducts] = useState<Product[]>(MOCK_PRODUCTS);

  // Store Design State
  const [storeDesign, setStoreDesign] = useState({
    coverImage: 'https://images.unsplash.com/photo-1441986300917-64674bd600d8?q=80&w=2070',
    themeColor: '#000000',
    layoutStyle: 'grid', // grid, editorial, minimal
    featuredCollection: 'New Season',
    announcementBar: 'Free Shipping on all orders over $500',
    showAnnouncement: true,
    aboutTitle: 'Our Philosophy',
    aboutContent: "Founded in 2023, Maison Margaux explores the intersection of brutalist architecture and fluid drapery. We believe in slow fashion, ethical production, and the power of the silhouette.\n\nEach piece is constructed in our Paris atelier using deadstock fabrics and sustainable organic fibers.",
    pressItems: [
      { id: '1', outlet: 'Vogue Paris', title: 'The Rising Star of 2024', date: 'Oct 2023', url: '#' },
      { id: '2', outlet: 'Hypebeast', title: 'Sustainable Luxury Redefined', date: 'Sept 2023', url: '#' },
      { id: '3', outlet: 'WWD', title: 'Paris Fashion Week Highlights', date: 'Aug 2023', url: '#' }
    ]
  });

  const [previewTab, setPreviewTab] = useState<'COLLECTION' | 'ABOUT' | 'PRESS'>('COLLECTION');

  // Sync initialTab prop
  useEffect(() => {
    if (initialTab) {
      setActiveTab(initialTab);
    }
  }, [initialTab]);

  // Form State for Upload
  const [newProduct, setNewProduct] = useState<Partial<Product>>({
    name: '',
    price: 0,
    category: 'Outerwear',
    description: '',
    image: '',
    designer: 'Maison Margaux', // Hardcoded for demo
    stock: 1,
    sizes: ['S', 'M', 'L']
  });

  const handleUpload = (e: React.FormEvent) => {
    e.preventDefault();
    const product: Product = {
      id: `new-${Date.now()}`,
      name: newProduct.name || 'Untitled Piece',
      price: newProduct.price || 0,
      category: newProduct.category || 'Uncategorized',
      description: newProduct.description || '',
      image: newProduct.image || 'https://picsum.photos/600/800', // Fallback
      designer: newProduct.designer || 'Maison Margaux',
      rating: 0,
      stock: newProduct.stock || 1,
      isNewSeason: true,
      sizes: newProduct.sizes || ['M']
    };
    setLocalProducts([product, ...localProducts]);
    setActiveTab('PRODUCTS');
    // Reset form
    setNewProduct({
        name: '',
        price: 0,
        category: 'Outerwear',
        description: '',
        image: '',
        designer: 'Maison Margaux',
        stock: 1,
        sizes: ['S', 'M', 'L']
    });
  };

  const toggleSize = (size: string) => {
    const currentSizes = newProduct.sizes || [];
    if (currentSizes.includes(size)) {
        setNewProduct({...newProduct, sizes: currentSizes.filter(s => s !== size)});
    } else {
        setNewProduct({...newProduct, sizes: [...currentSizes, size]});
    }
  };

  const generateAiDescription = () => {
    // Simulation of AI generation
    setNewProduct({
      ...newProduct,
      description: "A transcendental piece featuring architectural pleats and a structured silhouette. Crafted from ethically sourced organic silk, this garment embodies the duality of modern chaos and serene minimalism."
    });
  };

  const getSidebarItems = () => {
    if (isBuyer) {
      return [
        { id: 'OVERVIEW', label: 'Overview', icon: LayoutDashboard },
        { id: 'ORDERS', label: 'My Orders', icon: Package },
        { id: 'MARKETPLACE', label: 'Shop Now', icon: ShoppingBag, action: () => onNavigate('MARKETPLACE') },
        { id: 'PROFILE', label: 'Profile', icon: Settings },
      ];
    }
    // Explicitly type the array to allow optional 'action' property, preventing TS error on push
    const items: { id: string; label: string; icon: any; action?: () => void }[] = [
      { id: 'OVERVIEW', label: 'Overview', icon: LayoutDashboard },
      { id: 'PRODUCTS', label: 'My Collection', icon: Shirt },
      { id: 'UPLOAD', label: 'Add New Piece', icon: Plus },
      { id: 'ORDERS', label: 'Orders', icon: ShoppingBag },
    ];
    if (isVendor) {
      items.push({ id: 'STORE_DESIGN', label: 'Design Store', icon: Palette });
      items.push({ id: 'MARKETPLACE', label: 'View Storefront', icon: Eye, action: () => onNavigate('DESIGNERS') }); // In a real app, this would go to own profile
    }
    if (isAdmin) {
      items.push({ id: 'SETTINGS', label: 'Platform Settings', icon: Settings });
    } else {
      items.push({ id: 'PROFILE', label: 'Profile Settings', icon: Settings });
    }
    return items;
  };

  const renderSidebar = () => (
    <div className="w-full md:w-64 bg-white border-r border-gray-100 min-h-screen p-6 fixed md:relative z-10 hidden md:block">
