import React, { useState } from 'react';
import { createRoot } from 'react-dom/client';
import { Layout } from './components/Layout';
import { LandingView } from './components/LandingView';
import { MarketplaceView } from './components/MarketplaceView';
import { NewArrivalsView } from './components/NewArrivalsView';
import { DesignersView } from './components/DesignersView';
import { VendorProfileView } from './components/VendorProfileView';
import { ProductDetail } from './components/ProductDetail';
import { Dashboard } from './components/Dashboard';
import { AuthView } from './components/AuthView';
import { FeatureFlags, Product, UserRole, ViewState, Vendor, CartItem, Order } from './types';
import { MOCK_VENDORS, MOCK_PRODUCTS, MOCK_ORDERS } from './constants';

const App: React.FC = () => {
  // State
  const [currentView, setCurrentView] = useState<ViewState>('LANDING');
  const [userRole, setUserRole] = useState<UserRole>(UserRole.BUYER);
  // Track if user is "officially" logged in for UI purposes
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [selectedVendor, setSelectedVendor] = useState<Vendor | null>(null);
  const [selectedDesignerFilter, setSelectedDesignerFilter] = useState<string | null>(null);

  // Data State
  const [vendors, setVendors] = useState<Vendor[]>(MOCK_VENDORS);
  const [orders, setOrders] = useState<Order[]>(MOCK_ORDERS);

  // Derived State: Active Products (only from active vendors)
  const activeProducts = MOCK_PRODUCTS.filter(product => {
      const vendor = vendors.find(v => v.name === product.designer);
      return vendor ? vendor.subscriptionStatus === 'ACTIVE' : true; // Default to true if no vendor found (e.g. mock data mismatch)
  });

  // Feature Flags Management
  const [featureFlags, setFeatureFlags] = useState<FeatureFlags>({
    enableMarketplace: true,
    enableReviews: true,
    enableAiStyleMatch: true,
    maintenanceMode: false
  });

  // Handlers
  const handleNavigate = (view: ViewState) => {
    // Reset filters when navigating away from Marketplace/Designers unless specified
    if (view !== 'MARKETPLACE') {
        setSelectedDesignerFilter(null);
    }
    setCurrentView(view);
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setIsCartOpen(false);
  };

  const handleDesignerSelect = (designerName: string) => {
    // Try to find the full vendor object
    const vendor = vendors.find(v => v.name === designerName);
    if (vendor) {
      setSelectedVendor(vendor);
      handleNavigate('VENDOR_PROFILE');
    } else {
      // Fallback to simple filtering if no profile exists
      setSelectedDesignerFilter(designerName);
      handleNavigate('MARKETPLACE');
    }
  };

  const handleLogin = (role: UserRole) => {
    setUserRole(role);
    setIsLoggedIn(true);
    // Redirect based on role
    if (role === UserRole.ADMIN) {
      handleNavigate('ADMIN_PANEL');
    } else if (role === UserRole.VENDOR) {
      handleNavigate('VENDOR_DASHBOARD');
    } else {
      handleNavigate('MARKETPLACE');
    }
  };

  const handleLogout = () => {
    setIsLoggedIn(false);
    setUserRole(UserRole.BUYER);
    handleNavigate('LANDING');
  };

  const handleProductSelect = (product: Product) => {
    setSelectedProduct(product);
    handleNavigate('PRODUCT_DETAIL');
  };

  const handleAddToCart = (product: Product, size: string, measurements?: string) => {
    const newItem: CartItem = {
      ...product,
      quantity: 1,
      size: size,
      measurements: measurements || ''
    };
    setCart([...cart, newItem]);
    setIsCartOpen(true); // Open cart when item added
  };

  const handleUpdateCartItem = (index: number, updates: Partial<CartItem>) => {
    const newCart = [...cart];
    newCart[index] = { ...newCart[index], ...updates };
    setCart(newCart);
  };

  const handleRemoveFromCart = (index: number) => {
    const newCart = [...cart];
    newCart.splice(index, 1);
    setCart(newCart);
  };

  const toggleFeatureFlag = (key: keyof FeatureFlags) => {
    setFeatureFlags(prev => ({ ...prev, [key]: !prev[key] }));
  };

  const handleUpdateOrderStatus = (orderId: string, status: Order['status']) => {
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status } : o));
  };

  // View Routing
  const renderView = () => {
    if (currentView === 'AUTH') {
      return <AuthView onLogin={handleLogin} onNavigate={handleNavigate} />;
    }

    if (featureFlags.maintenanceMode && userRole !== UserRole.ADMIN) {
      return (
        <div className="h-screen flex items-center justify-center flex-col">
          <h1 className="text-4xl font-serif">LUMIERRE</h1>
          <p className="mt-4 uppercase tracking-widest text-sm">Under Maintenance</p>
        </div>
      );
    }

    switch (currentView) {
      case 'LANDING':
        return <LandingView onNavigate={handleNavigate} isLoggedIn={isLoggedIn} userRole={userRole} />;
      case 'MARKETPLACE':
        return (
          <MarketplaceView 
            onNavigate={handleNavigate} 
            onProductSelect={handleProductSelect} 
            initialDesigner={selectedDesignerFilter}
            products={activeProducts}
            vendors={vendors}
          />
        );
      case 'NEW_ARRIVALS':
        return <NewArrivalsView onProductSelect={handleProductSelect} products={activeProducts} />;
      case 'DESIGNERS':
        return <DesignersView onSelectDesigner={handleDesignerSelect} vendors={vendors} />;
      case 'VENDOR_PROFILE':
        return selectedVendor ? (
          <VendorProfileView 
            vendor={selectedVendor} 
            onProductSelect={handleProductSelect}
            onNavigate={handleNavigate}
            products={activeProducts}
          />
        ) : <DesignersView onSelectDesigner={handleDesignerSelect} vendors={vendors} />;
      case 'PRODUCT_DETAIL':
        return selectedProduct ? (
          <ProductDetail 
            product={selectedProduct} 
            onAddToCart={handleAddToCart} 
            onBack={() => handleNavigate('MARKETPLACE')}
            featureFlags={featureFlags}
          />
        ) : (
            <MarketplaceView 
                onNavigate={handleNavigate} 
                onProductSelect={handleProductSelect} 
                products={activeProducts}
                vendors={vendors}
            />
        );
      case 'VENDOR_DASHBOARD':
      case 'ADMIN_PANEL':
      case 'BUYER_DASHBOARD':
        return (
          <Dashboard 
            role={userRole} 
            featureFlags={featureFlags} 
            toggleFeatureFlag={toggleFeatureFlag}
            onNavigate={handleNavigate}
            vendors={vendors}
            setVendors={setVendors}
            orders={orders}
            onUpdateOrderStatus={handleUpdateOrderStatus}
          />
        );
      case 'PROFILE_SETTINGS':
        return (
          <Dashboard 
            role={userRole} 
            featureFlags={featureFlags} 
            toggleFeatureFlag={toggleFeatureFlag}
            onNavigate={handleNavigate}
            initialTab="PROFILE"
            vendors={vendors}
            setVendors={setVendors}
          />
        );
      default:
        return <LandingView onNavigate={handleNavigate} isLoggedIn={isLoggedIn} userRole={userRole} />;
    }
  };

  if (currentView === 'AUTH') {
    return renderView();
  }

  return (
    <Layout 
      role={userRole} 
      cart={cart}
      isCartOpen={isCartOpen}
      setIsCartOpen={setIsCartOpen}
      onUpdateCartItem={handleUpdateCartItem}
      onRemoveFromCart={handleRemoveFromCart}
      onNavigate={handleNavigate}
      onRoleChange={setUserRole}
      currentView={currentView}
      isLoggedIn={isLoggedIn}
      onLogout={handleLogout}
    >
      {renderView()}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Filter, ChevronDown, Heart } from 'lucide-react';
import { Product, ViewState, Vendor } from '../types';

interface MarketplaceViewProps {
  onProductSelect: (product: Product) => void;
  onNavigate: (view: ViewState) => void;
  initialDesigner?: string | null;
  products: Product[];
  vendors: Vendor[];
}

const FILTERS = ['All', 'Outerwear', 'Bottoms', 'Knitwear', 'Footwear', 'Accessories'];

export const MarketplaceView: React.FC<MarketplaceViewProps> = ({ 
  onProductSelect, 
  initialDesigner, 
  products,
  vendors
}) => {
  const [activeCategory, setActiveCategory] = useState('All');
  const [activeDesigner, setActiveDesigner] = useState('All Designers');

  // Handle initial filter from props
  useEffect(() => {
    if (initialDesigner) {
      setActiveDesigner(initialDesigner);
    } else {
        setActiveDesigner('All Designers');
    }
  }, [initialDesigner]);

  // Extract unique active designers from passed products
  const designers = useMemo(() => {
    const unique = Array.from(new Set(products.map(p => p.designer)));
    return ['All Designers', ...unique.sort()];
  }, [products]);

  const filteredProducts = products.filter(p => {
    const matchesCategory = activeCategory === 'All' || p.category === activeCategory;
    const matchesDesigner = activeDesigner === 'All Designers' || p.designer === activeDesigner;
    return matchesCategory && matchesDesigner;
  });

  return (
    <div className="min-h-screen pt-12 pb-24">
      {/* Header & Filters */}
      <div className="max-w-7xl mx-auto px-6 mb-12 sticky top-20 z-30 bg-white/80 backdrop-blur-sm py-6 border-b border-gray-100/50 transition-all">
        <div className="flex flex-col gap-8">

          {/* Top Row: Title + Designer Select */}
          <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
            <h1 className="text-4xl font-serif italic">Ready-to-Wear</h1>

            {/* Designer Dropdown */}
            <div className="relative min-w-[240px]">
              <label className="text-[10px] uppercase tracking-widest text-gray-400 mb-2 block font-bold">Filter by Designer</label>
              <div className="relative group">
                <select 
                  value={activeDesigner}
                  onChange={(e) => setActiveDesigner(e.target.value)}
                  className="w-full appearance-none bg-transparent border-b border-gray-300 py-2 pr-8 text-sm font-bold uppercase tracking-widest focus:outline-none focus:border-black cursor-pointer hover:border-luxury-gold transition-colors"
                >
                  {designers.map(d => (
                    <option key={d} value={d}>{d}</option>
                  ))}
                </select>
                <ChevronDown size={14} className="absolute right-0 top-1/2 -translate-y-1/2 pointer-events-none text-gray-400 group-hover:text-black transition-colors" />
              </div>
            </div>
          </div>

          {/* Bottom Row: Category Pills */}
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3 overflow-x-auto w-full pb-2 scrollbar-hide">
              {FILTERS.map(cat => (
                <button
                  key={cat}
                  onClick={() => setActiveCategory(cat)}
                  className={`text-xs uppercase tracking-widest whitespace-nowrap px-6 py-2 border rounded-full transition-all duration-300 ${
                    activeCategory === cat 
                      ? 'bg-black text-white border-black' 
                      : 'bg-transparent text-gray-500 border-gray-200 hover:border-black hover:text-black'
                  }`}
                >
                  {cat}
                </button>
              ))}
            </div>
             <button className="hidden md:flex items-center gap-2 text-xs uppercase font-bold ml-4 border-l pl-6 border-gray-200 hover:text-luxury-gold transition-colors whitespace-nowrap">
              <Filter size={14} /> More Filters
            </button>
          </div>

        </div>
      </div>

      {/* Grid */}
      <div className="max-w-7xl mx-auto px-6">
        {filteredProducts.length === 0 ? (
           <div className="py-24 text-center animate-fade-in">
             <p className="text-xl font-serif italic text-gray-400 mb-4">No pieces found matching your criteria.</p>
             <button 
               onClick={() => {setActiveCategory('All'); setActiveDesigner('All Designers');}} 
               className="text-xs font-bold uppercase border-b border-black pb-1 hover:text-luxury-gold hover:border-luxury-gold transition-colors"
             >
               Clear Filters
             </button>
           </div>
        ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-x-6 gap-y-16 animate-fade-in">
          {filteredProducts.map((product) => (
            <div 
              key={product.id} 
              className="group cursor-pointer"
              onClick={() => onProductSelect(product)}
            >
              <div className="relative aspect-[3/4] overflow-hidden bg-gray-100 mb-6">
                <img 
                  src={product.image} 
                  alt={product.name} 
                  className="w-full h-full object-cover transition-transform duration-700 ease-out group-hover:scale-110"
                />

                {/* Overlay Action */}
                <div className="absolute inset-0 bg-black/10 transition-opacity duration-500 opacity-0 group-hover:opacity-100 flex items-end justify-center pb-8">
                  <button className="bg-white text-black text-xs font-bold uppercase tracking-widest px-8 py-3 hover:bg-luxury-black hover:text-white transition-all duration-500 shadow-xl transform translate-y-4 opacity-0 group-hover:translate-y-0 group-hover:opacity-100">
                    Quick View
                  </button>
                </div>

                <button className="absolute top-4 right-4 text-white mix-blend-difference hover:scale-110 transition-transform opacity-0 group-hover:opacity-100 duration-500">
                  <Heart size={20} strokeWidth={1.5} />
                </button>
              </div>

              <div className="flex justify-between items-start">
                <div>
                  <h3 className="text-xs font-bold uppercase tracking-widest mb-1">{product.designer}</h3>
                  <p className="font-serif text-gray-600 italic group-hover:text-black transition-colors">{product.name}</p>
                </div>
                <span className="text-sm font-medium">${product.price}</span>
              </div>
            </div>
          ))}
        </div>
        )}
      </div>
    </div>
  );
};

