  { id: 'f1', name: 'Sophie L.', handle: '@sophie_style', avatar: 'https://images.unsplash.com/photo-1438761681033-6461ffad8d80?q=80&w=150&auto=format&fit=crop', since: 'Oct 2023' },
  { id: 'f2', name: 'Arthur B.', handle: '@art_b', avatar: 'https://images.unsplash.com/photo-1500648767791-00dcc994a43e?q=80&w=150&auto=format&fit=crop', since: 'Nov 2023' },
  { id: 'f3', name: 'Chloé M.', handle: '@chloe_paris', avatar: 'https://images.unsplash.com/photo-1544005313-94ddf0286df2?q=80&w=150&auto=format&fit=crop', since: 'Dec 2023' },
  { id: 'f4', name: 'James D.', handle: '@jd_design', avatar: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?q=80&w=150&auto=format&fit=crop', since: 'Jan 2024' },
];

export const Dashboard: React.FC<DashboardProps> = ({ 
  role, 
  featureFlags, 
  toggleFeatureFlag, 
  onNavigate, 
  initialTab,
  vendors = [],
  setVendors,
  orders = [],
  onUpdateOrderStatus,
  products = MOCK_PRODUCTS,
  onAddProduct
}) => {
  const isAdmin = role === UserRole.ADMIN;
  const isVendor = role === UserRole.VENDOR;
  const isBuyer = role === UserRole.BUYER;

  // Assume current vendor is Maison Margaux for demo purposes if logged in as Vendor
  const currentVendor = isVendor ? vendors.find(v => v.name === 'Maison Margaux') : null;
  const isSubscribed = currentVendor?.subscriptionStatus === 'ACTIVE';

  const [activeTab, setActiveTab] = useState<DashboardTab>('OVERVIEW');
  const [savedItems, setSavedItems] = useState<Product[]>(products.slice(0, 3)); 
  const [followers, setFollowers] = useState(MOCK_FOLLOWERS);

  // Store Design State
  const [storeDesign, setStoreDesign] = useState({
    brandName: 'Maison Margaux',
    location: 'Paris, France',
    coverImage: 'https://images.unsplash.com/photo-1441986300917-64674bd600d8?q=80&w=2070',
    themeColor: '#000000',
    bio: "Founded in 2023, Maison Margaux explores the intersection of brutalist architecture and fluid drapery. We believe in slow fashion, ethical production, and the power of the silhouette.\n\nEach piece is constructed in our Paris atelier using deadstock fabrics and sustainable organic fibers."
  });

  // Form State for Upload
  const [newProduct, setNewProduct] = useState<Partial<Product>>({
    name: '',
    price: 0,
    category: 'Outerwear',
    description: '',
    image: '',
    designer: 'Maison Margaux', 
    stock: 1,
    sizes: ['S', 'M', 'L']
  });

  // Filter products for the current vendor view
  const vendorProducts = isVendor 
    ? products.filter(p => p.designer === 'Maison Margaux')
    : products; // Admin sees all (or logic could differ)

  useEffect(() => {
    if (initialTab) setActiveTab(initialTab);
  }, [initialTab]);

  const handleUpload = (e: React.FormEvent) => {
    e.preventDefault();
    if (!isSubscribed) {
        alert("Please subscribe to publish products.");
        return;
    }
    const product: Product = {
      id: `new-${Date.now()}`,
      name: newProduct.name || 'Untitled Piece',
      price: newProduct.price || 0,
      category: newProduct.category || 'Uncategorized',
      description: newProduct.description || '',
      image: newProduct.image || 'https://picsum.photos/600/800',
      designer: newProduct.designer || 'Maison Margaux',
      rating: 0,
      stock: newProduct.stock || 1,
      isNewSeason: true,
      sizes: newProduct.sizes || ['M']
    };

    if (onAddProduct) {
        onAddProduct(product);
    }

    setActiveTab('PRODUCTS');
    setNewProduct({ name: '', price: 0, category: 'Outerwear', description: '', image: '', designer: 'Maison Margaux', stock: 1, sizes: ['S', 'M', 'L'] });
  };

  const removeFromSaved = (id: string) => {
    setSavedItems(prev => prev.filter(p => p.id !== id));
  };

  const removeFollower = (id: string) => {
    setFollowers(prev => prev.filter(f => f.id !== id));
  };

  const handleSubscriptionToggle = (vendorId: string) => {
    if (!setVendors) return;
    const updatedVendors = vendors.map(v => {
      if (v.id === vendorId) {
        return { ...v, subscriptionStatus: v.subscriptionStatus === 'ACTIVE' ? 'INACTIVE' : 'ACTIVE' } as Vendor;
      }
      return v;
    });
    setVendors(updatedVendors);
  };

  const handleVendorSelfSubscribe = () => {
    if (currentVendor && setVendors) {
        // Simulate payment process
        const updatedVendors = vendors.map(v => {
            if (v.id === currentVendor.id) {
                return { ...v, subscriptionStatus: 'ACTIVE' } as Vendor;
            }
            return v;
        });
        setVendors(updatedVendors);
    }
  };

  const getSidebarItems = () => {
    if (isBuyer) {
      return [
        { id: 'OVERVIEW', label: 'Overview', icon: LayoutDashboard },
        { id: 'ORDERS', label: 'My Orders', icon: Package },
        { id: 'SAVED', label: 'Saved Items', icon: Heart },
        { id: 'MARKETPLACE', label: 'Shop Now', icon: ShoppingBag, action: () => onNavigate('MARKETPLACE') },
        { id: 'PROFILE', label: 'Profile', icon: Settings },
      ];
    }
    const items: { id: string; label: string; icon: any; action?: () => void }[] = [
      { id: 'OVERVIEW', label: 'Overview', icon: LayoutDashboard },
      { id: 'PRODUCTS', label: 'My Collection', icon: Shirt },
      { id: 'UPLOAD', label: 'Add New Piece', icon: Plus },
    ];

    if (isVendor) {
      items.push({ id: 'FULFILLMENT', label: 'Delivery & Orders', icon: Truck });
      items.push({ id: 'FOLLOWERS', label: 'Followers', icon: Users });
      items.push({ id: 'STORE_DESIGN', label: 'Design Store', icon: Palette });
      items.push({ id: 'SAVED', label: 'Saved Items', icon: Heart });
      items.push({ id: 'MARKETPLACE', label: 'View Storefront', icon: Eye, action: () => onNavigate('DESIGNERS') });
      items.push({ id: 'PROFILE', label: 'Subscription & Profile', icon: CreditCard });
    }

    if (isAdmin) {
      items.push({ id: 'ORDERS', label: 'All Orders', icon: Package });
      items.push({ id: 'SUBSCRIPTIONS', label: 'Subscriptions', icon: Users });
      items.push({ id: 'SETTINGS', label: 'Platform Settings', icon: Settings });
    }
    return items;
  };

  const renderSidebar = () => (
    <div className="w-full md:w-64 bg-white border-r border-gray-100 min-h-screen p-6 fixed md:relative z-10 hidden md:block">
      <div className="mb-12">
        <h2 className="text-xl font-serif font-bold italic">Atelier.</h2>
        <p className="text-xs text-gray-400 uppercase tracking-widest mt-1">{role} Portal</p>
      </div>

      <nav className="space-y-2">
        {getSidebarItems().map((item) => (
          <button
            key={item.id}
            onClick={() => item.action ? item.action() : setActiveTab(item.id as DashboardTab)}
            className={`w-full flex items-center gap-3 px-4 py-3 text-xs font-bold uppercase tracking-widest transition-all rounded-sm ${
              activeTab === item.id 
                ? 'bg-black text-white shadow-lg' 
                : 'text-gray-500 hover:bg-gray-50 hover:text-black'
            }`}
          >
            <item.icon size={16} />
            {item.label}
            {item.id === 'MARKETPLACE' && <ArrowUpRight size={14} className="ml-auto" />}
          </button>
        ))}
      </nav>

      {isVendor && !isSubscribed && (
         <div className="mt-8 p-4 bg-luxury-gold/10 border border-luxury-gold/20 rounded-sm">
            <h4 className="text-xs font-bold uppercase tracking-widest text-luxury-gold mb-2">Account Inactive</h4>
            <p className="text-[10px] text-gray-600 mb-3">Subscribe to publish your items to the marketplace.</p>
            <button 
                onClick={handleVendorSelfSubscribe}
                className="w-full bg-luxury-gold text-white py-2 text-[10px] font-bold uppercase tracking-widest hover:bg-black transition-colors"
            >
                Subscribe Now
            </button>
         </div>
      )}
    </div>
  );

  const renderFulfillment = () => {
    // Filter orders to only those containing items from the current vendor
    const vendorOrders = orders.filter(order => 
       order.items.some(item => item.designer === currentVendor?.name)
    ).map(order => ({
        ...order,
        // Only show items relevant to this vendor
        items: order.items.filter(item => item.designer === currentVendor?.name)
    }));

    return (
    <div className="bg-white p-8 rounded-sm shadow-sm border border-gray-100 animate-slide-up">
       <h3 className="text-xl font-serif italic mb-2">Order Fulfillment</h3>
       <p className="text-gray-500 text-sm mb-8">Manage logistics and delivery status for your clientele.</p>

       <div className="space-y-4">
          {vendorOrders.map((order) => (
              <div key={order.id} className="border border-gray-100 p-6 rounded-sm flex flex-col md:flex-row justify-between items-start gap-6">
                 <div className="flex-1">
                    <div className="flex items-center gap-4 mb-2">
                        <span className="font-bold text-lg">{order.id}</span>
                        <span className="text-xs text-gray-500 uppercase tracking-wide">{order.date}</span>
                        <span className={`px-2 py-1 text-[10px] font-bold uppercase tracking-wide rounded ${
                            order.status === 'Delivered' ? 'bg-green-50 text-green-700' : 
                            order.status === 'Shipped' ? 'bg-blue-50 text-blue-700' : 'bg-yellow-50 text-yellow-700'
                        }`}>
                            {order.status}
                        </span>
                    </div>
                    <p className="text-sm font-bold mb-4">Client: {order.customerName}</p>
                    <div className="space-y-2">
                        {order.items.map((item, idx) => (
                            <div key={idx} className="flex items-center gap-4 bg-gray-50 p-2">
                                <img src={item.image} className="w-10 h-10 object-cover" alt="product"/>
                                <div>
                                    <p className="text-xs font-bold uppercase">{item.name}</p>
                                    <p className="text-[10px] text-gray-500">Size: {item.size} | Qty: {item.quantity}</p>
                                </div>
                            </div>
                        ))}
                    </div>
                 </div>

                 <div className="w-full md:w-48 shrink-0">
                    <label className="text-xs text-gray-500 uppercase tracking-widest mb-2 block">Update Status</label>
                    <select 
                        value={order.status}
                        onChange={(e) => onUpdateOrderStatus && onUpdateOrderStatus(order.id, e.target.value as any)}
                        className="w-full p-2 border border-gray-200 text-sm focus:border-black outline-none mb-2"
                    >
                        <option value="Processing">Processing</option>
                        <option value="Shipped">Shipped</option>
                        <option value="Delivered">Delivered</option>
                    </select>
                    <button className="w-full bg-black text-white py-2 text-xs font-bold uppercase tracking-widest hover:bg-gray-800">
                        Print Label
                    </button>
                 </div>
              </div>
          ))}
          {vendorOrders.length === 0 && (
              <div className="text-center py-12 text-gray-400">
                  <p>No active orders to fulfill.</p>
              </div>
          )}
       </div>
    </div>
    );
  };

  const renderFollowers = () => (
    <div className="bg-white p-8 rounded-sm shadow-sm border border-gray-100 animate-slide-up">
        <h3 className="text-xl font-serif italic mb-2">Community & Followers</h3>
        <p className="text-gray-500 text-sm mb-8">Engage with your brand's loyal following.</p>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {followers.map(follower => (
                <div key={follower.id} className="border border-gray-100 p-6 flex items-center justify-between group hover:border-black transition-colors">
                    <div className="flex items-center gap-4">
                        <img src={follower.avatar} alt={follower.name} className="w-12 h-12 rounded-full object-cover" />
                        <div>
                            <p className="font-bold text-sm">{follower.name}</p>
                            <p className="text-xs text-gray-400">{follower.handle}</p>
                            <p className="text-[10px] text-gray-300 mt-1">Joined {follower.since}</p>
                        </div>
                    </div>
                    <button 
                        onClick={() => removeFollower(follower.id)}
                        className="text-gray-300 hover:text-red-500 transition-colors p-2"
                        title="Remove Follower"
                    >
                        <UserX size={16} />
                    </button>
                </div>
            ))}
             {followers.length === 0 && (
              <div className="col-span-full text-center py-12 text-gray-400">
                  <p>No followers yet.</p>
              </div>
          )}
        </div>
    </div>
  );

  const renderSubscriptions = () => (
    <div className="bg-white p-8 rounded-sm shadow-sm border border-gray-100 animate-slide-up">
        <h3 className="text-xl font-serif italic mb-8">Vendor Subscriptions</h3>
        <div className="overflow-x-auto">
            <table className="w-full text-left">
                <thead className="border-b border-gray-100">
                    <tr>
                        <th className="pb-4 text-xs font-bold uppercase tracking-wider text-gray-400">Vendor</th>
                        <th className="pb-4 text-xs font-bold uppercase tracking-wider text-gray-400">Status</th>
                        <th className="pb-4 text-xs font-bold uppercase tracking-wider text-gray-400">Verification</th>
                        <th className="pb-4 text-xs font-bold uppercase tracking-wider text-gray-400 text-right">Action</th>
                    </tr>
                </thead>
                <tbody className="divide-y divide-gray-50">
                    {vendors.map((vendor) => (
                        <tr key={vendor.id}>
                            <td className="py-4">
                                <div className="flex items-center gap-3">
                                    <img src={vendor.avatar} className="w-8 h-8 rounded-full object-cover" alt={vendor.name} />
                                    <span className="font-bold text-sm">{vendor.name}</span>
                                </div>
                            </td>
                            <td className="py-4">
                                <span className={`px-2 py-1 rounded text-[10px] font-bold uppercase tracking-wide ${
                                    vendor.subscriptionStatus === 'ACTIVE' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'
                                }`}>
                                    {vendor.subscriptionStatus}
                                </span>
                            </td>
                            <td className="py-4">
                                {vendor.verified ? <span className="text-blue-500"><CheckCircle size={14} /></span> : <span className="text-gray-300">-</span>}
                            </td>
                            <td className="py-4 text-right">
                                <button 
                                    onClick={() => handleSubscriptionToggle(vendor.id)}
                                    className="text-xs font-bold underline hover:text-luxury-gold"
                                >
                                    {vendor.subscriptionStatus === 'ACTIVE' ? 'Suspend' : 'Activate'}
                                </button>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    </div>
  );

  const renderProfile = () => (
    <div className="bg-white p-8 rounded-sm shadow-sm border border-gray-100 animate-slide-up">
      <h3 className="text-xl font-serif italic mb-8">Profile & Settings</h3>

      {isVendor && (
          <div className="mb-8 p-6 bg-gray-50 border border-gray-100 flex justify-between items-center">
              <div>
                  <h4 className="text-sm font-bold uppercase tracking-widest mb-1">Membership Status</h4>
                  <p className="text-xs text-gray-500">{isSubscribed ? 'Your designer account is active.' : 'Your account is inactive. Products will not be visible.'}</p>
              </div>
              <div>
                  {isSubscribed ? (
                      <span className="flex items-center gap-2 text-green-600 font-bold text-xs uppercase tracking-widest">
                          <CheckCircle size={16} /> Active
                      </span>
                  ) : (
                      <button 
                        onClick={handleVendorSelfSubscribe}
                        className="bg-luxury-gold text-white px-6 py-3 text-xs font-bold uppercase tracking-widest hover:bg-black transition-colors"
                      >
                          Subscribe Now
                      </button>
                  )}
              </div>
          </div>
      )}

      {/* Standard Profile Fields */}
      <div className="max-w-2xl space-y-6">
        <div className="flex items-center gap-6 pb-6 border-b border-gray-50">
          <div className="w-24 h-24 bg-gray-100 rounded-full overflow-hidden shrink-0">
             <img src="https://images.unsplash.com/photo-1534528741775-53994a69daeb?q=80&w=200" alt="Avatar" className="w-full h-full object-cover" />
          </div>
          <div>
            <h4 className="font-bold text-lg">{role === 'VENDOR' ? 'Maison Margaux' : 'Jane Doe'}</h4>
            <p className="text-gray-400 text-sm mb-2">{role}</p>
            <button className="text-xs font-bold uppercase tracking-widest bg-gray-100 px-4 py-2 hover:bg-black hover:text-white transition-colors">
              Change Avatar
            </button>
          </div>
        </div>

         <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
           <div className="space-y-2">
             <label className="text-xs text-gray-500 uppercase tracking-widest">Display Name</label>
             <input type="text" defaultValue={role === 'VENDOR' ? 'Maison Margaux' : 'Jane Doe'} className="w-full p-3 border border-gray-200 bg-gray-50 text-sm focus:border-black outline-none" />
           </div>
           <div className="space-y-2">
             <label className="text-xs text-gray-500 uppercase tracking-widest">Email Address</label>
             <input type="email" defaultValue="contact@lumierre.com" className="w-full p-3 border border-gray-200 bg-gray-50 text-sm focus:border-black outline-none" />
           </div>
        </div>
      </div>
    </div>
  );

  const renderOrders = () => (
      <div className="bg-white p-8 rounded-sm shadow-sm border border-gray-100 animate-slide-up">
        <h3 className="text-sm font-bold uppercase tracking-widest mb-6">Recent Orders</h3>
        <ul className="space-y-4">
          {[1, 2, 3, 4, 5].map(i => (
            <li key={i} className="flex justify-between items-start text-sm border-b border-gray-50 pb-6 last:pb-0 last:border-0">
              <div className="flex items-start gap-4">
                <div className="w-16 h-20 bg-gray-100 shrink-0">
                   <img src={`https://picsum.photos/seed/${i}order/300/400`} className="w-full h-full object-cover" alt="Order"/>
                </div>
                <div>
                  <p className="font-bold text-base mb-1">Order #492{i}</p>
                  <p className="text-xs text-gray-500 mb-2">Placed on Oct 12, 2023</p>
                  <div className="flex flex-col gap-1">
                     <span className="text-xs text-gray-700">1 x Structure Knit Sweater</span>
                     <span className="text-xs text-gray-700">1 x Minimalist Tote</span>
                  </div>
                </div>
              </div>
              <div className="flex flex-col items-end gap-2">
                 <span className="font-bold">$1,250.00</span>
                 <span className={`px-2 py-1 text-[10px] font-bold uppercase tracking-wide rounded ${
                   i === 1 ? 'bg-green-50 text-green-700' : 'bg-yellow-50 text-yellow-700'
                 }`}>
                   {i === 1 ? 'Delivered' : 'Processing'}
                 </span>
                 <button className="text-xs underline text-gray-400 mt-2 hover:text-black">View Details</button>
              </div>
            </li>
          ))}
        </ul>
      </div>
  );

  const renderOverview = () => {
      if (isBuyer) {
       return (
        <div className="space-y-8 animate-fade-in">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white p-6 rounded-sm shadow-sm border border-gray-100">
               <div className="flex justify-between items-start mb-4">
                  <div className="p-2 rounded-full bg-gray-50 text-black">
                    <Package size={20} />
                  </div>
               </div>
               <h3 className="text-2xl font-bold mb-1">12</h3>
               <p className="text-xs text-gray-500 uppercase tracking-wide">Orders Placed</p>
            </div>
            <div className="bg-white p-6 rounded-sm shadow-sm border border-gray-100">
               <div className="flex justify-between items-start mb-4">
                  <div className="p-2 rounded-full bg-gray-50 text-black">
                    <DollarSign size={20} />
                  </div>
               </div>
               <h3 className="text-2xl font-bold mb-1">$4,850</h3>
               <p className="text-xs text-gray-500 uppercase tracking-wide">Total Spent</p>
            </div>
             <div className="bg-white p-6 rounded-sm shadow-sm border border-gray-100 cursor-pointer group hover:border-black transition-colors" onClick={() => onNavigate('MARKETPLACE')}>
               <div className="flex justify-between items-start mb-4">
                  <div className="p-2 rounded-full bg-gray-50 text-black group-hover:bg-black group-hover:text-white transition-colors">
                    <ShoppingBag size={20} />
                  </div>
               </div>
               <h3 className="text-2xl font-bold mb-1">Shop</h3>
               <p className="text-xs text-gray-500 uppercase tracking-wide">Browse New Arrivals</p>
            </div>
          </div>
        </div>
       )
    }

    return (
    <div className="space-y-8 animate-fade-in">
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {[
          { label: 'Total Revenue', value: '$124,500', icon: DollarSign, color: 'text-green-600' },
          { label: 'Active Orders', value: '45', icon: Package, color: 'text-blue-600' },
          { label: 'Total Views', value: '89.2K', icon: Activity, color: 'text-purple-600' },
          { label: isAdmin ? 'Active Vendors' : 'Followers', value: isAdmin ? '12' : followers.length.toString(), icon: Users, color: 'text-orange-600' },
        ].map((stat, i) => (
          <div key={i} className="bg-white p-6 rounded-sm shadow-sm border border-gray-100">
            <div className="flex justify-between items-start mb-4">
              <div className={`p-2 rounded-full bg-gray-50 ${stat.color}`}>
                <stat.icon size={20} />
              </div>
              <span className="text-xs text-green-500 font-bold">+12%</span>
            </div>
            <h3 className="text-2xl font-bold mb-1">{stat.value}</h3>
            <p className="text-xs text-gray-500 uppercase tracking-wide">{stat.label}</p>
          </div>
        ))}
      </div>
       <div className="bg-white p-8 rounded-sm shadow-sm border border-gray-100">
        <h3 className="text-sm font-bold uppercase tracking-widest mb-8">Performance Analytics</h3>
        <div className="h-80 w-full">
          <ResponsiveContainer width="100%" height="100%">
            <AreaChartComponent data={SALES_DATA} />
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  )};

  const renderProducts = () => (
    <div className="bg-white p-8 rounded-sm shadow-sm border border-gray-100 animate-slide-up">
      <div className="flex justify-between items-center mb-8">
        <h3 className="text-xl font-serif italic">Current Collection</h3>
        <button 
          onClick={() => setActiveTab('UPLOAD')}
          className="flex items-center gap-2 bg-black text-white px-4 py-2 text-xs font-bold uppercase tracking-widest hover:bg-luxury-gold transition-colors"
        >
          <Plus size={16} /> Add Piece
        </button>
      </div>
      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead className="border-b border-gray-100">
            <tr>
              <th className="pb-4 text-xs font-bold uppercase tracking-wider text-gray-400">Product</th>
              <th className="pb-4 text-xs font-bold uppercase tracking-wider text-gray-400">Price</th>
              <th className="pb-4 text-xs font-bold uppercase tracking-wider text-gray-400">Stock</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-50">
            {vendorProducts.map((product) => (
              <tr key={product.id}>
                <td className="py-4 font-serif">{product.name}</td>
                <td className="py-4 text-sm">${product.price}</td>
                <td className="py-4 text-sm">{product.stock}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );

  const renderSaved = () => (
    <div className="bg-white p-8 rounded-sm shadow-sm border border-gray-100 animate-slide-up">
      <h3 className="text-xl font-serif italic mb-8">Saved Items</h3>
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {savedItems.map(item => (
            <div key={item.id} className="relative border border-gray-100 p-4">
                <img src={item.image} className="w-full aspect-[3/4] object-cover mb-2" />
                <p className="font-bold text-xs uppercase">{item.name}</p>
                <button onClick={() => removeFromSaved(item.id)} className="absolute top-2 right-2 p-1 bg-white rounded-full"><Trash2 size={12}/></button>
            </div>
        ))}
      </div>
    </div>
  );

  const renderUpload = () => (
    <div className="bg-white p-8 rounded-sm shadow-sm border border-gray-100">
        <h3 className="text-xl font-serif italic mb-8">Upload</h3>
        <form onSubmit={handleUpload} className="space-y-4">
            <input type="text" placeholder="Name" className="w-full border-b p-2" value={newProduct.name} onChange={e => setNewProduct({...newProduct, name: e.target.value})} />
            <input type="number" placeholder="Price" className="w-full border-b p-2" value={newProduct.price || ''} onChange={e => setNewProduct({...newProduct, price: Number(e.target.value)})} />
            <button type="submit" className="bg-black text-white px-6 py-2 uppercase text-xs font-bold">Publish</button>
        </form>
    </div>
  );

  const renderStoreDesign = () => (
    <div className="bg-white p-8 rounded-sm shadow-sm border border-gray-100 animate-slide-up">
        <h3 className="text-xl font-serif italic mb-8">Storefront Design</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-6">
                 <div className="space-y-2">
                    <label className="text-xs text-gray-500 uppercase tracking-widest">Brand Name</label>
                    <input 
                        type="text" 
                        value={storeDesign.brandName} 
                        onChange={e => setStoreDesign({...storeDesign, brandName: e.target.value})}
                        className="w-full p-3 border border-gray-200 bg-gray-50 text-sm focus:border-black outline-none"
                    />
                 </div>
                 <div className="space-y-2">
                    <label className="text-xs text-gray-500 uppercase tracking-widest">Location</label>
                    <input 
                        type="text" 
                        value={storeDesign.location} 
                        onChange={e => setStoreDesign({...storeDesign, location: e.target.value})}
                        className="w-full p-3 border border-gray-200 bg-gray-50 text-sm focus:border-black outline-none"
                    />
                 </div>
                 <div className="space-y-2">
                    <label className="text-xs text-gray-500 uppercase tracking-widest">Brand Bio</label>
                    <textarea 
                        value={storeDesign.bio} 
                        onChange={e => setStoreDesign({...storeDesign, bio: e.target.value})}
                        rows={6}
                        className="w-full p-3 border border-gray-200 bg-gray-50 text-sm focus:border-black outline-none resize-none"
                    />
                 </div>
                 <button className="bg-black text-white px-6 py-3 text-xs font-bold uppercase tracking-widest hover:bg-luxury-gold transition-colors">
                    Save Changes
                 </button>
            </div>

            <div>
                 <label className="text-xs text-gray-500 uppercase tracking-widest mb-2 block">Cover Image</label>
                 <div className="relative aspect-video bg-gray-100 overflow-hidden mb-4 group cursor-pointer">
                    <img src={storeDesign.coverImage} className="w-full h-full object-cover group-hover:opacity-75 transition-opacity" alt="Cover" />
                    <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                         <Camera size={24} className="text-white drop-shadow-lg" />
                    </div>
                 </div>
                 <label className="text-xs text-gray-500 uppercase tracking-widest mb-2 block">Theme Preview</label>
                 <div className="border border-gray-100 p-4">
                     <h4 className="font-serif italic text-lg mb-1">{storeDesign.brandName}</h4>
                     <p className="text-xs text-gray-400">{storeDesign.location}</p>
                 </div>
            </div>
        </div>
    </div>
  );

  const renderSettings = () => (
      <div className="bg-white p-8">
          <h3 className="text-xl font-serif italic">Settings</h3>
          <p className="text-gray-400 text-sm">Platform controls...</p>
      </div>
  );

  return (
    <div className="min-h-screen bg-luxury-cream flex flex-col md:flex-row">
      {renderSidebar()}
      <div className="flex-1 p-6 md:p-12 overflow-y-auto">
        <div className="max-w-6xl mx-auto">
           {/* Mobile Header Logic same as before... */}
           <div className="md:hidden mb-8 flex items-center justify-between">
            <h1 className="text-2xl font-serif italic">Atelier.</h1>
           </div>

          <div className="mb-8">
            <h1 className="text-3xl font-serif font-medium mb-2 capitalize">
              {activeTab === 'MARKETPLACE' ? 'Marketplace' : activeTab.toLowerCase().replace('_', ' ')}
            </h1>
          </div>

          {activeTab === 'OVERVIEW' && renderOverview()}
          {activeTab === 'PRODUCTS' && renderProducts()}
          {activeTab === 'UPLOAD' && renderUpload()}
          {activeTab === 'ORDERS' && renderOrders()}
          {activeTab === 'SETTINGS' && isAdmin && renderSettings()}
          {activeTab === 'PROFILE' && renderProfile()}
          {activeTab === 'STORE_DESIGN' && renderStoreDesign()}
          {activeTab === 'SAVED' && renderSaved()}
          {activeTab === 'FULFILLMENT' && isVendor && renderFulfillment()}
          {activeTab === 'SUBSCRIPTIONS' && isAdmin && renderSubscriptions()}
          {activeTab === 'FOLLOWERS' && renderFollowers()}
        </div>
      </div>
    </div>
  );
};

