                        <button 
                            onClick={() => handleEditProduct(product)} 
                            className="p-2 text-gray-400 hover:text-blue-600 transition-colors" 
                            title="Edit"
                        >
                            <Edit2 size={16} />
                        </button>
                         <button 
                            onClick={() => {
                                if (window.confirm('Are you sure you want to remove this item?')) {
                                    onDeleteProduct && onDeleteProduct(product.id);
                                }
                            }}
                            className="p-2 text-gray-400 hover:text-red-500 transition-colors" 
                            title="Delete"
                        >
                            <Trash2 size={16} />
                        </button>
                    </div>
                </td>
              </tr>
            ))}
            {vendorProducts.length === 0 && (
                <tr>
                    <td colSpan={5} className="py-12 text-center text-gray-400 italic">No items in your collection.</td>
                </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );

  const renderSaved = () => (
    <div className="bg-white p-8 rounded-sm shadow-sm border border-gray-100 animate-slide-up">
      <h3 className="text-xl font-serif italic mb-8">Saved Items</h3>
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {savedItems.map(item => (
            <div key={item.id} className="relative border border-gray-100 p-4">
                <img src={item.image} className="w-full aspect-[3/4] object-cover mb-2" />
                <p className="font-bold text-xs uppercase">{item.name}</p>
                <button onClick={() => removeFromSaved(item.id)} className="absolute top-2 right-2 p-1 bg-white rounded-full"><Trash2 size={12}/></button>
            </div>
        ))}
      </div>
    </div>
  );

  const renderUpload = () => (
    <div className="bg-white p-8 rounded-sm shadow-sm border border-gray-100">
        <div className="flex justify-between items-center mb-8">
            <h3 className="text-xl font-serif italic">{isEditing ? 'Edit Piece' : 'Upload New Piece'}</h3>
            {isEditing && (
                <button 
                    onClick={handleCancelEdit}
                    className="text-xs uppercase font-bold text-gray-500 hover:text-black flex items-center gap-1"
                >
                    <X size={14} /> Cancel Editing
                </button>
            )}
        </div>
        <form onSubmit={handleUpload} className="space-y-6 max-w-2xl">
            <div className="space-y-2">
                <label className="text-xs text-gray-500 uppercase tracking-widest">Product Name</label>
                <input type="text" placeholder="e.g. Asymmetric Silk Trench" className="w-full border p-3 text-sm focus:border-black outline-none" value={newProduct.name} onChange={e => setNewProduct({...newProduct, name: e.target.value})} required />
            </div>

            <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                    <label className="text-xs text-gray-500 uppercase tracking-widest">Price ($)</label>
                    <input type="number" placeholder="0.00" className="w-full border p-3 text-sm focus:border-black outline-none" value={newProduct.price || ''} onChange={e => setNewProduct({...newProduct, price: Number(e.target.value)})} required />
                </div>
                <div className="space-y-2">
                     <label className="text-xs text-gray-500 uppercase tracking-widest">Category</label>
                     <select 
                        className="w-full border p-3 text-sm focus:border-black outline-none bg-white"
                        value={newProduct.category} 
                        onChange={e => setNewProduct({...newProduct, category: e.target.value})}
                     >
                         <option value="Outerwear">Outerwear</option>
                         <option value="Bottoms">Bottoms</option>
                         <option value="Knitwear">Knitwear</option>
                         <option value="Footwear">Footwear</option>
                         <option value="Accessories">Accessories</option>
                         <option value="Clothing">Clothing</option>
                     </select>
                </div>
            </div>

             <div className="space-y-2">
                <label className="text-xs text-gray-500 uppercase tracking-widest">Description</label>
                <textarea rows={4} placeholder="Describe the materials, fit, and design philosophy..." className="w-full border p-3 text-sm focus:border-black outline-none resize-none" value={newProduct.description} onChange={e => setNewProduct({...newProduct, description: e.target.value})} />
            </div>

            <button type="submit" className="bg-black text-white px-8 py-3 uppercase text-xs font-bold tracking-widest hover:bg-luxury-gold transition-colors">
                {isEditing ? 'Save Changes' : 'Publish Collection'}
            </button>
        </form>
    </div>
  );

  const renderStoreDesign = () => (
    <div className="bg-white p-8 rounded-sm shadow-sm border border-gray-100 animate-slide-up">
        <h3 className="text-xl font-serif italic mb-8">Storefront Design</h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="space-y-6">
                 <div className="space-y-2">
                    <label className="text-xs text-gray-500 uppercase tracking-widest">Brand Name</label>
                    <input 
                        type="text" 
                        value={storeDesign.brandName} 
                        onChange={e => setStoreDesign({...storeDesign, brandName: e.target.value})}
                        className="w-full p-3 border border-gray-200 bg-gray-50 text-sm focus:border-black outline-none"
                    />
                 </div>
                 <div className="space-y-2">
                    <label className="text-xs text-gray-500 uppercase tracking-widest">Location</label>
                    <input 
                        type="text" 
                        value={storeDesign.location} 
                        onChange={e => setStoreDesign({...storeDesign, location: e.target.value})}
                        className="w-full p-3 border border-gray-200 bg-gray-50 text-sm focus:border-black outline-none"
                    />
                 </div>
                 <div className="space-y-2">
                    <label className="text-xs text-gray-500 uppercase tracking-widest">Brand Bio</label>
                    <textarea 
                        value={storeDesign.bio} 
                        onChange={e => setStoreDesign({...storeDesign, bio: e.target.value})}
                        rows={6}
                        className="w-full p-3 border border-gray-200 bg-gray-50 text-sm focus:border-black outline-none resize-none"
                    />
                 </div>
                 <button 
                    onClick={handleSaveStoreDesign}
                    className="bg-black text-white px-6 py-3 text-xs font-bold uppercase tracking-widest hover:bg-luxury-gold transition-colors"
                 >
                    Save Changes
                 </button>
            </div>

            <div>
                 <label className="text-xs text-gray-500 uppercase tracking-widest mb-2 block">Cover Image</label>
                 <div className="relative aspect-video bg-gray-100 overflow-hidden mb-4 group cursor-pointer">
                    <img src={storeDesign.coverImage} className="w-full h-full object-cover group-hover:opacity-75 transition-opacity" alt="Cover" />
                    <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                         <Camera size={24} className="text-white drop-shadow-lg" />
                    </div>
                 </div>
                 <label className="text-xs text-gray-500 uppercase tracking-widest mb-2 block">Theme Preview</label>
                 <div className="border border-gray-100 p-4">
                     <h4 className="font-serif italic text-lg mb-1">{storeDesign.brandName}</h4>
                     <p className="text-xs text-gray-400">{storeDesign.location}</p>
                 </div>
            </div>
        </div>
    </div>
  );

  const renderSettings = () => (
      <div className="bg-white p-8">
          <h3 className="text-xl font-serif italic">Settings</h3>
          <p className="text-gray-400 text-sm">Platform controls...</p>
      </div>
  );

  return (
    <div className="min-h-screen bg-luxury-cream flex flex-col md:flex-row">
      {renderSidebar()}
      <div className="flex-1 p-6 md:p-12 overflow-y-auto">
        <div className="max-w-6xl mx-auto">
           {/* Mobile Header Logic same as before... */}
           <div className="md:hidden mb-8 flex items-center justify-between">
            <h1 className="text-2xl font-serif italic">Atelier.</h1>
           </div>

          <div className="mb-8">
            <h1 className="text-3xl font-serif font-medium mb-2 capitalize">
              {activeTab === 'MARKETPLACE' ? 'Marketplace' : activeTab === 'SUBSCRIPTION_PLAN' ? 'My Subscription' : activeTab.toLowerCase().replace('_', ' ')}
            </h1>
          </div>

          {activeTab === 'OVERVIEW' && renderOverview()}
          {activeTab === 'PRODUCTS' && renderProducts()}
          {activeTab === 'UPLOAD' && renderUpload()}
          {activeTab === 'ORDERS' && renderOrders()}
          {activeTab === 'SETTINGS' && isAdmin && renderSettings()}
          {activeTab === 'PROFILE' && renderProfile()}
          {activeTab === 'STORE_DESIGN' && renderStoreDesign()}
          {activeTab === 'SAVED' && renderSaved()}
          {activeTab === 'FULFILLMENT' && isVendor && renderFulfillment()}
          {activeTab === 'SUBSCRIPTIONS' && isAdmin && renderSubscriptions()}
          {activeTab === 'FOLLOWERS' && renderFollowers()}
          {activeTab === 'SUBSCRIPTION_PLAN' && renderSubscriptionPlan()}
        </div>
      </div>
    </div>
  );
};

